      ''');
    }
  }

  Future<void> _handleNotificationRequest(String message) async {
    try {
      final Map<String, dynamic> data = jsonDecode(message);
      final String action = data['action'] ?? '';

      switch (action) {
        case 'requestPermission':
          final settings = await _firebaseMessaging.requestPermission(
            alert: true,
            announcement: false,
            badge: true,
            carPlay: false,
            criticalAlert: false,
            provisional: false,
            sound: true,
          );
          final granted =
              settings.authorizationStatus == AuthorizationStatus.authorized;
          _controller.runJavaScript('''
            if (window.onNativeNotificationPermission) {
              window.onNativeNotificationPermission({
                granted: $granted,
                status: '${settings.authorizationStatus.name}'
              });
            }
          ''');
          break;

        case 'getToken':
          final token = await _firebaseMessaging.getToken();
          _controller.runJavaScript('''
            if (window.onNativePushToken) {
              window.onNativePushToken({
                success: true,
                token: '${token ?? ''}'
              });
            }
          ''');
          break;

        case 'subscribe':
          final topic = data['topic'] ?? '';
          if (topic.isNotEmpty) {
            await _firebaseMessaging.subscribeToTopic(topic);
            _controller.runJavaScript('''
              if (window.onNativeTopicSubscription) {
                window.onNativeTopicSubscription({
                  success: true,
                  action: 'subscribe',
                  topic: '$topic'
                });
              }
            ''');
          }
          break;

        case 'unsubscribe':
          final topic = data['topic'] ?? '';
          if (topic.isNotEmpty) {
            await _firebaseMessaging.unsubscribeFromTopic(topic);
            _controller.runJavaScript('''
              if (window.onNativeTopicSubscription) {
                window.onNativeTopicSubscription({
                  success: true,
                  action: 'unsubscribe',
                  topic: '$topic'
                });
              }
            ''');
          }
          break;
      }
    } catch (e) {
      debugPrint('Error handling notification request: $e');
    }
  }

