      debugPrint('Foreground message received: ${message.messageId}');
      final title =
          message.notification?.title?.replaceAll("'", "\\'") ?? '';
      final body =
          message.notification?.body?.replaceAll("'", "\\'") ?? '';
      final data = jsonEncode(message.data).replaceAll("'", "\\'");

      _controller.runJavaScript('''
